--
-- Create model FloridaDocketEntry
--
CREATE TABLE "search_floridadocketentry" ("id" integer NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "date_created" timestamp with time zone NOT NULL, "date_modified" timestamp with time zone NOT NULL, "date_filed" timestamp with time zone NULL, "date_submitted" timestamp with time zone NULL, "entry_type" smallint NOT NULL, "entry_type_raw" text NOT NULL, "entry_name" text NOT NULL, "description" text NOT NULL, "status" text NOT NULL, "docket_entry_uuid" uuid NOT NULL, "docket_id" integer NOT NULL, "submitted_by_id" integer NULL);
COMMENT ON COLUMN "search_floridadocketentry"."date_filed" IS 'The filing date indicated by Florida ACIS';
COMMENT ON COLUMN "search_floridadocketentry"."date_submitted" IS 'Pulled directly from Florida results';
COMMENT ON COLUMN "search_floridadocketentry"."entry_type" IS 'Mirror of Juriscraper `DocketEntryType` enum.';
COMMENT ON COLUMN "search_floridadocketentry"."entry_type_raw" IS 'Value of `entry_type_raw` in Juriscraper results. Pulled from Florida API with no modification.';
COMMENT ON COLUMN "search_floridadocketentry"."entry_name" IS 'Pulled directly from Florida results';
COMMENT ON COLUMN "search_floridadocketentry"."description" IS 'Pulled directly from Florida results';
COMMENT ON COLUMN "search_floridadocketentry"."status" IS 'Pulled directly from Florida''s `entry_status` field';
COMMENT ON COLUMN "search_floridadocketentry"."docket_entry_uuid" IS 'Pulled directly from Florida results';
COMMENT ON COLUMN "search_floridadocketentry"."docket_id" IS 'The Docket this entry is associated with.';
COMMENT ON COLUMN "search_floridadocketentry"."submitted_by_id" IS 'FK to the case party that submitted this document.';
