CREATE TABLE "search_floridadocument" ("id" integer NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "date_created" timestamp with time zone NOT NULL, "date_modified" timestamp with time zone NOT NULL, "sha1" varchar(40) NOT NULL, "page_count" integer NULL, "file_size" integer NULL, "filepath_local" varchar(1000) NOT NULL, "filepath_ia" varchar(1000) NOT NULL, "ia_upload_failure_count" smallint NULL, "thumbnail" varchar(100) NULL, "thumbnail_status" smallint NOT NULL, "plain_text" text NOT NULL, "ocr_status" smallint NULL, "content_type" varchar(63) NOT NULL, "document_name" text NOT NULL, "document_type" text NOT NULL, "description" text NOT NULL, "link_uuid" uuid NOT NULL, "url" varchar(250) NOT NULL, "processing_error" smallint NULL, "docket_entry_id" integer NOT NULL);
COMMENT ON COLUMN "search_floridadocument"."content_type" IS 'The MIME type indicated by Florida ACIS';
COMMENT ON COLUMN "search_floridadocument"."document_name" IS 'The name of the document in Florida ACIS';
COMMENT ON COLUMN "search_floridadocument"."document_type" IS 'The type of the document in Florida ACIS';
